// Script Continued Below
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
	function isValidRequest(data) {
		if (!data.user_sys_id || data.user_sys_id=='' ||
			!data.item_sys_id || data.item_sys_id=='' ||
			!data.table || data.table=='') {
			return false;
		}
		return true;
	}

	var data = request.body.data;
	if (!isValidRequest(data)) {
		response.setStatus(400);
		response.setBody({ errorMessage: "Invalid request, missing required fields or services." });
		return;
	}

	var result;
	try {
		var userInfo = new UserInfoScripts();
		var lProfile = userInfo.loadProfileInfo(data.user_sys_id);
		var photo = userInfo.loadPhotoInfo(data.user_sys_id, false);
		lProfile.photo = photo.photo;
		var chatInfo = new api_dtech_chat().getChatInformation(lProfile.email + ",dshilkret@discovertechnologies.com", data.user_sys_id, data.table, data.item_sys_id);
		lProfile.chatInfo = chatInfo;
		result = {};
		result.userProfile = lProfile;
	} catch (e) {
		response.setStatus(500);
		response.setBody({ errorMessage: e.message });
		return;
	}

	response.setStatus(200);
	response.setBody(result);
	response.setContentType('application/json');

})(request, response);
